package org.eclipse.rdf4j.query.algebra.evaluation.function.string;

import static org.junit.jupiter.api.Assertions.assertThrows;

import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.evaluation.ValueExprEvaluationException;
import org.junit.jupiter.api.Test;

public class ContainsTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	private final Contains contains = new Contains();

	@Test
	public void differentBaseDirectionsAreIncompatible() {
		Literal source = VF.createLiteral("abc", "en", Literal.BaseDirection.LTR);
		Literal needle = VF.createLiteral("b", "en", Literal.BaseDirection.RTL);

		assertThrows(ValueExprEvaluationException.class, () -> contains.evaluate(VF, source, needle));
	}
}
